import { Observable } from 'kr-observable';

export class Person extends Observable {
    id;
    name;
    lastMessage = null;
    rooms = new Set();
    status = 'Online';
    
    constructor(id, name) {
        super()
        this.id = id;
        this.name = name;
    }

    setName(name) {
        this.name = name;
    }

    setLastMessage(message) {
        this.lastMessage = message;
    }

    addRoom(room) {
        this.rooms.add(room);
    }

    removeRoom(room) {
        this.rooms.delete(room);
    }

    setStatus(status) {
        this.status = status;
        this.rooms.forEach(room => {
            room.addStatusUpdate(this, status);
        });
    }
}
